clear functions %clear all%%%%%%%%% INITIALIZE PARAMETERS %%%%%%%Mechanical parameters.m1  =  1;    m2 =  1;  % massesI1  =  0.5;  I2 = 0.5;  % inertias about cmsl   =  1;              % length of linksa   =  .5;            % dist. from O to G1 and E to G2 (see figures)g   =  10;% Initial conditions and other settings.Ts = 0.005;      % simulation sample time in secondsT  = 5;         % duration of animation  in secondstspan = [0:Ts:T];q1    = 0;  % angle made by link1 with verticalu1    = 0;  % abslolute velocity of link1   q2    = 0;  % angle made by link2 with verticalu2    = 0;  % abslolute velocity of link2z = zeros(length(tspan),4);Tau = zeros(length(tspan),2);z(1,:)=[q1 u1 q2 u2];options=odeset('abstol',1e-9,'reltol',1e-9);figure(1)i = 0;for t = tspan(2:end)    pause(0.00000001);    i = i+1;    xm1=l*sin(z(i,1));%-l*sin(z(i,1));%modified by cxc in Jan. 2018    ym1=-l*cos(z(i,1));    xm2=l*sin(z(i,1)) + l*sin(z(i,1)+z(i,3));%xm1-l*sin(z(i,3));%modified by cxc in Jan. 2018    ym2=-l*cos(z(i,1))-l*cos(z(i,1)+z(i,3));       plot([0],[0],'ko','MarkerSize',3); %pivot point    hold on    plot([0 xm1],[0 ym1],'r','LineWidth',2);% first pendulum    plot([xm1 xm2],[ym1 ym2],'b','LineWidth',2);% second pendulum    axis([-2*l 2*l -2*l 2*l]);    axis square    title(sprintf('t = %.3fs',t));    hold off    F(i)=getframe(gcf);        %%%%%%% INTEGRATOR or ODE SOLVER %%%%%%%    % Disturbance toruqes    T_dis = [100*(rand(1)-0.5); 100*(rand(1)-0.5)];    T = qp_controller(z(i,:) , m1, m2, I1, I2, l, a, g);    Tau(i+1,:) = T';        [~,zs] = ode113('dbpend_rhs_qp',[0,Ts],z(i,:),options, ...                          m1, m2, I1, I2, l, a, g, T+T_dis);    z(i+1,:) = zs(end,:);end%%%%%%%%% POSTPROCESSING %%%%%%%%%%%%%%%%% A routine to animate the results% To speed up change the framespersecondv = VideoWriter('dbpend.avi');v.FrameRate = 1/Ts;open(v);writeVideo(v,F);close(v);%Get some plotsfigure(2)plot(tspan,z(:,1),tspan,z(:,3));xlabel('time (s)'); ylabel('position (rad)');%%% energy check, Total energy should be constant%%% here we plot successive difference in total energies (should be zero)%%% NOTE: %%% a) energy difference can not be better than the ode tolerance. %%%    This is one way to check if simulations are alright. %%% b) This is not true if the system is actuated or there are dissipative%%%    forces like dampers. The TE here consists of conservative forces. for i=1:length(tspan)    [KE(i), PE(i)] = dbpend_energy(tspan(i),z(i,:),m1, m2, I1, I2, l, a, g);endTE = KE + PE;TE_diff = diff(TE);figure(3)plot(tspan(1:end-1),TE_diff)% figure(4)% plot(t,z(:,1),t,.1*cos(sqrt(g/l)*t));% xlabel('time (s)'); ylabel('position (rad)');figure(5)plot(tspan,Tau); 